import json
from anthropic import Anthropic

client = Anthropic()

EXTRACT_PROMPT = """
Extract key information from this conversation into JSON with these fields:
{
  "user_name": null or string,
  "stated_goals": [],
  "decisions_made": [],
  "open_questions": [],
  "key_facts": {},
  "next_steps": []
}
Only include what was explicitly stated. Use null for unknown fields.
Respond with valid JSON only.
"""

def extract_facts(messages: list[dict]) -> dict:
    text = "\n".join(f"{m['role'].upper()}: {m['content']}" for m in messages)
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=512,
        system=EXTRACT_PROMPT.strip(),
        messages=[{"role": "user", "content": text}],
    )
    try:
        return json.loads(resp.content[0].text)
    except json.JSONDecodeError:
        return {}

# Example output for a conversation about building an e-commerce site:
# {
#   "user_name": "Alice",
#   "stated_goals": ["build an e-commerce site", "launch by Q3"],
#   "decisions_made": ["use FastAPI", "use PostgreSQL"],
#   "open_questions": ["payment provider?"],
#   "key_facts": {"app_name": "MyShop", "tech_stack": "FastAPI + PostgreSQL"},
#   "next_steps": ["set up database schema"]
# }

class StructuredSummaryMemory:
    def __init__(self, system: str, extract_every: int = 5):
        self.system = system
        self.extract_every = extract_every
        self._facts: dict = {}
        self._recent: list[dict] = []
        self._turn_count: int = 0

    def _facts_as_context(self) -> str:
        if not self._facts:
            return ""
        return (
            "[Known facts from earlier in the conversation]\n"
            + json.dumps(self._facts, indent=2)
        )

    def chat(self, user_text: str) -> str:
        msgs = []
        if self._facts:
            msgs.append({"role": "user", "content": self._facts_as_context()})
            msgs.append({"role": "assistant", "content": "Understood. I have that context."})
        msgs.extend(self._recent)
        msgs.append({"role": "user", "content": user_text})

        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=1024,
            system=self.system,
            messages=msgs,
        )
        reply = resp.content[0].text
        self._recent.extend([
            {"role": "user", "content": user_text},
            {"role": "assistant", "content": reply},
        ])
        self._turn_count += 1

        if self._turn_count % self.extract_every == 0:
            new_facts = extract_facts(self._recent[-self.extract_every * 2:])
            # Merge new facts into existing facts
            for k, v in new_facts.items():
                if v and not self._facts.get(k):
                    self._facts[k] = v
                elif isinstance(v, list) and v:
                    self._facts.setdefault(k, [])
                    self._facts[k] = list(set(self._facts[k] + v))
            self._recent = self._recent[-4:]   # keep only 2 recent pairs

        return reply
